    r"|20\d{2}\s*(?:年|estimates?|forecasts?|\bE\b)"
    r"|\d{2}\s*\bE\b"
    r"|(?:Q[1-4]|[1-4]Q)\s*(?:FY\s*)?(?:20\d{2}|\d{2})\s*E?"
    r"|(?:20\d{2}|\d{2})\s*(?:Q[1-4])"
    r"|20\d{2}\s+Q[1-4]"
    r"|\d+\s*(?:個月|月|months?|m|年|years?|週|weeks?|天|days?)"
